#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[1005];
        scanf("%s", S);
        int len = strlen(S);
        char password[1005];
        strcpy(password, S);
        int hasDigit = 0, hasSpecial = 0;
        for (int i = 0; i < len; ++i) {
            if (isdigit((unsigned char)password[i])) hasDigit = 1;
            else if (!isalnum((unsigned char)password[i])) hasSpecial = 1;
        }
        if (!hasDigit) {
            for (int i = 0; i < len; ++i) {
                if (!isdigit((unsigned char)password[i])) {
                    password[i] = '1';
                    break;
                }
            }
        }
        if (!hasSpecial) {
            for (int i = 0; i < len; ++i) {
                if (isalnum((unsigned char)password[i])) {
                    password[i] = '!';
                    break;
                }
            }
        }
        printf("%s %s\n", S, password);
    }
    return 0;
}

