import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0])
    out_lines = []
    for i in range(1, T + 1):
        S = data[i].rstrip('\n')
        pwd = list(S)
        has_digit = any(ch.isdigit() for ch in pwd)
        has_special = any(not ch.isalnum() for ch in pwd)
        if not has_digit:
            for idx, ch in enumerate(pwd):
                if not ch.isdigit():
                    pwd[idx] = '1'
                    break
        if not has_special:
            for idx, ch in enumerate(pwd):
                if ch.isalnum():
                    pwd[idx] = '!'
                    break
        out_lines.append(f"{S} {''.join(pwd)}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

