const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++], 10);
let output = [];
for (let t = 0; t < T; ++t) {
  const S = lines[idx++] || '';
  let pwdArr = S.split('');
  let hasDigit = false, hasSpecial = false;
  for (const ch of pwdArr) {
    if (/[0-9]/.test(ch)) hasDigit = true;
    else if (!/[a-zA-Z0-9]/.test(ch)) hasSpecial = true;
  }
  if (!hasDigit) {
    for (let i = 0; i < pwdArr.length; ++i) {
      if (!/[0-9]/.test(pwdArr[i])) { pwdArr[i] = '1'; break; }
    }
  }
  if (!hasSpecial) {
    for (let i = 0; i < pwdArr.length; ++i) {
      if (/[a-zA-Z0-9]/.test(pwdArr[i])) { pwdArr[i] = '!'; break; }
    }
  }
  output.push(`${S} ${pwdArr.join('')}`);
}
